import { useState, useEffect } from 'react';

interface Product {
  id: number;
  name: string;
  price: number;
  image: string;
}

const useProducts = () => {
  const [products, setProducts] = useState<Product[]>([]);

  useEffect(() => {
    // Simulate fetching data from an API
    const fetchProducts = async () => {
      const data: Product[] = [
        {
          id: 1,
          name: 'Apple',
          price: 1.5,
          image: 'https://images.unsplash.com/photo-1567306226416-28f0efdc88ce?w=400',
        },
        {
          id: 2,
          name: 'Banana',
          price: 0.5,
          image: 'https://images.unsplash.com/photo-1574226516831-e1dff420e9a0?w=400',
        },
        {
          id: 3,
          name: 'Carrot',
          price: 0.8,
          image: 'https://images.unsplash.com/photo-1582515073490-dc7b2a3d1f3b?w=400',
        },
      ];
      setProducts(data);
    };

    fetchProducts();
  }, []);

  return products;
};

export default useProducts;

